			reports := []agent.ExecuteBeadReport{
				tc.first,
				{
					Status:        agent.ExecuteBeadStatusSuccess,
					OutcomeReason: "",
					ActualPower:   10,
				},
			}
			idx := 0
			report, err := runEscalatingPowerAttempts(
				context.Background(),
				5,
				testEscalationLadder{floors: []int{10, 20}},
