		}
		if runtime.Log != nil {
			_, _ = fmt.Fprint(runtime.Log, workLog.FormatLifecycleLine(WorkLogLifecycleLine{
				Phase:    "readiness",

	suggestedAction := "check the readiness route or harness configuration and retry"
	if rootMutationError {
