				"idle_count":   preClaimIdleStreak,
			}
			for k, v := range preClaimDecisionAudit("preclaim_idle_escalation", preClaimIdleStreak) {
				payload[k] = v
			}
			emit("loop.operator_attention", payload)
			if runtime.Log != nil {
