				testEscalationLadder{floors: []int{10, 20}},
				func(_ context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
					requested = append(requested, requestedMinPower)
					if idx >= len(reports) {
						return reports[len(reports)-1], nil
